139	/// Per-invocation finalize inputs — the clap-free shape the
140	/// `finalize` op works against. Built from `FinalizeArgs` at the
141	/// binary edge via `TryFrom` (fallible only on repo-path
142	/// canonicalization — `--squash` is already parsed into a
143	/// `SquashSpec` by clap). The `--log` path lives on `Context`,
144	/// not here.
145	#[derive(Debug)]
146	pub struct FinalizeParams {
147	    pub repo: PathBuf,
148	    pub squash: Option<SquashSpec>,
149	    pub delay_secs: f64,
150	    pub bookmark: Option<String>,
