159	    /// Derive `push`/`bookmark` from `--push` and canonicalize
160	    /// `--repo` (so the detached child resolves it regardless of
161	    /// cwd); `--squash` was already parsed by clap.
162	    fn try_from(a: &FinalizeArgs) -> Result<Self, String> {
163	        let repo = std::fs::canonicalize(&a.repo)
164	            .map_err(|e| format!("cannot resolve repo path '{}': {e}", a.repo.display()))?;
165	        Ok(FinalizeParams {
166	            repo,
167	            squash: a.squash.value.clone(),
168	            delay_secs: a.delay,
169	            bookmark: a.push.clone(),
170	            push: a.push.is_some(),
171	            detach: a.detach,
172	            exec: a.exec,
173	        })
