191	/// Validate inputs synchronously before detaching.
192	///
193	/// Catches the common failure modes up front so the parent can exit
194	/// with a visible non-zero status — rather than discovering them in
195	/// the detached child where errors only reach the log file.
196	fn preflight(params: &FinalizeParams) -> Result<(), Box<dyn std::error::Error>> {
197	    debug!("preflight: checking params");
198	    let repo_str = params.repo.to_string_lossy();
199	    let cwd = std::path::Path::new(".");
200	
201	    // Verify squash revsets resolve to something, and that the squash
202	    // won't drop source-only ochid: trailers.
203	    if let Some(ref sq) = params.squash {
204	        jj_rev_exists(&repo_str, cwd, &sq.source)
205	            .map_err(|e| format!("squash source '{}' does not resolve: {e}", sq.source))?;
206	        jj_rev_exists(&repo_str, cwd, &sq.target)
207	            .map_err(|e| format!("squash target '{}' does not resolve: {e}", sq.target))?;
208	        check_squash_keeps_ochids(&repo_str, cwd, sq)?;
209	    }
210	
211	    // Refuse to operate on a repo with conflicts.
212	    let conflicts = run(
213	        "jj",
214	        &[
215	            "log",
216	            "-r",
217	            "conflicts()",
218	            "--no-graph",
219	            "-T",
220	            "\"x\"",
221	            "-R",
222	            &repo_str,
223	        ],
224	        cwd,
225	    )?;
226	    if !conflicts.is_empty() {
227	        return Err(format!("repo '{repo_str}' has conflicts — resolve before finalize").into());
228	    }
229	
230	    // Bookmark: existence, tracking, forward-only move, push-target description.
231	    if let Some(ref bookmark) = params.bookmark {
232	        let exists = run("jj", &["bookmark", "list", bookmark, "-R", &repo_str], cwd)?;
233	        if exists.is_empty() {
234	            return Err(format!("bookmark '{bookmark}' does not exist").into());
235	        }
236	
237	        crate::common::verify_tracking(&params.repo, bookmark)?;
238	
239	        let target_rev = params
240	            .squash
241	            .as_ref()
242	            .map(|sq| sq.target.as_str())
243	            .unwrap_or("@"); // OK: no squash spec → bookmark will point at current @
244	        let range = run(
245	            "jj",
246	            &[
247	                "log",
248	                "-r",
249	                &format!("{bookmark}::({target_rev})"),
250	                "--no-graph",
251	                "-T",
252	                "\"x\"",
253	                "-R",
254	                &repo_str,
255	            ],
256	            cwd,
257	        )?;
258	        if range.is_empty() {
259	            return Err(format!(
260	                "bookmark '{bookmark}' move is not forward — current position is not an \
261	                 ancestor of '{target_rev}' (would diverge)"
262	            )
263	            .into());
264	        }
265	
266	        if params.push {
267	            let desc = run(
268	                "jj",
269	                &[
270	                    "log",
271	                    "-r",
272	                    target_rev,
273	                    "--no-graph",
274	                    "-T",
275	                    "description",
276	                    "-R",
277	                    &repo_str,
278	                ],
279	                cwd,
280	            )?;
281	            if desc.trim().is_empty() {
282	                return Err(format!(
283	                    "push target '{target_rev}' has no description — push would fail \
284	                     (run `jj describe -r {target_rev} -R {repo_str}` first)"
285	                )
286	                .into());
287	            }
288	        }
289	    }
290	
291	    log_plan(params)?;
292	
293	    Ok(())
294	}
