381	fn log_plan(params: &FinalizeParams) -> Result<(), Box<dyn std::error::Error>> {
382	    let repo_str = params.repo.to_string_lossy();
383	    let cwd = std::path::Path::new(".");
384	
385	    if let Some(ref sq) = params.squash {
386	        info!(
