408	/// Short one-line summary of a revset: `<change_short> <commit_short>`.
409	fn jj_rev_short(repo: &str, cwd: &std::path::Path, rev: &str) -> Result<String, String> {
410	    run(
411	        "jj",
412	        &[
413	            "log",
414	            "-r",
415	            rev,
416	            "--no-graph",
417	            "-T",
418	            "change_id.shortest(8) ++ \" \" ++ commit_id.shortest(8)",
419	            "-R",
420	            repo,
421	        ],
422	        cwd,
423	    )
424	    .map_err(|e| e.to_string())
425	}
426	
427	/// Do the squash / set-bookmark / push work — runs in the detached
428	/// child when `--detach`, inline otherwise.
429	fn finalize_exec(params: &FinalizeParams) -> Result<(), Box<dyn std::error::Error>> {
430	    debug!("finalize_exec: starting params={params:?}");
431	    let repo_str = params.repo.to_string_lossy();
432	    let cwd = std::path::Path::new(".");
433	
434	    // Squash if requested
435	    if let Some(ref sq) = params.squash {
436	        let delay = std::time::Duration::from_secs_f64(params.delay_secs);
437	        debug!("finalize_exec: sleeping {delay:?}");
438	        std::thread::sleep(delay);
439	
440	        // Re-check after the delay: a `jj describe` can land between
441	        // the parent's preflight and this point, so the pre-squash
442	        // state is the one that matters.
443	        check_squash_keeps_ochids(&repo_str, cwd, sq)?;
444	
445	        info!("finalize: squashing {} → {}...", sq.source, sq.target);
446	        run(
447	            "jj",
448	            &[
449	                "squash",
450	                "--ignore-immutable",
451	                "--use-destination-message",
452	                "--from",
453	                &sq.source,
454	                "--into",
455	                &sq.target,
456	                "-R",
457	                &repo_str,
458	            ],
459	            cwd,
460	        )?;
461	    }
462	
463	    // Set bookmark and push if requested
464	    if let Some(ref bookmark) = params.bookmark {
465	        // Verify bookmark exists — don't silently create new ones
466	        let result = run("jj", &["bookmark", "list", bookmark, "-R", &repo_str], cwd)?;
467	        if result.is_empty() {
468	            return Err(format!("bookmark '{bookmark}' does not exist").into());
469	        }
470	
471	        let rev = params
472	            .squash
473	            .as_ref()
474	            .map(|sq| sq.target.as_str())
475	            .unwrap_or("@"); // OK: no squash spec → bookmark points at current @
476	        info!("finalize: setting bookmark '{bookmark}' to {rev}...");
477	        run(
478	            "jj",
479	            &["bookmark", "set", bookmark, "-r", rev, "-R", &repo_str],
480	            cwd,
481	        )?;
482	
483	        if params.push {
484	            info!("finalize: pushing '{bookmark}' to origin...");
485	            run(
486	                "jj",
487	                &["git", "push", "--bookmark", bookmark, "-R", &repo_str],
488	                &params.repo,
489	            )?;
490	        }
491	    }
492	
493	    info!("finalize: done");
494	    debug!("finalize_exec: done");
495	    Ok(())
496	}
497	
498	/// Build the argv for the detached re-exec: `finalize --exec …`,
499	/// mirroring `params` plus the `--log` path so the child logs to
500	/// the same file.
501	pub fn build_exec_args(params: &FinalizeParams, log: Option<&Path>) -> Vec<String> {
502	    let mut args = vec![
503	        "finalize".to_string(),
504	        "--exec".to_string(),
505	        "--repo".to_string(),
506	        params.repo.to_string_lossy().to_string(),
507	    ];
508	    if let Some(ref sq) = params.squash {
509	        args.push("--squash".to_string());
510	        args.push(format!("{},{}", sq.source, sq.target));
511	        args.push("--delay".to_string());
512	        args.push(params.delay_secs.to_string());
513	    }
514	    if let Some(ref bookmark) = params.bookmark {
515	        args.push("--push".to_string());
516	        args.push(bookmark.clone());
517	    }
518	    if let Some(log) = log {
519	        args.push("--log".to_string());
520	        args.push(log.to_string_lossy().to_string());
521	    }
522	    args
523	}
524	
525	/// Spawn a detached child process with `--exec` and return immediately.
526	/// The child re-enters `main()`, parses `--exec`, and `finalize()` routes
527	/// it to `finalize_exec()` where the actual work happens.
528	fn detach(ctx: &Context, params: &FinalizeParams) -> Result<(), Box<dyn std::error::Error>> {
529	    debug!("detach: parent starting params={params:?}");
530	
531	    let exe = std::env::current_exe()?;
532	    let args = build_exec_args(params, ctx.log.as_deref());
533	    debug!("detach: exe={exe:?} args={args:?}");
534	
535	    let mut cmd = std::process::Command::new(exe);
536	    cmd.args(&args).stdin(Stdio::null());
537	
538	    // Hand the child the user's controlling terminal when one exists so
539	    // its output stays visible after the parent exits. Inherited pipes
540	    // are unreliable here — the bash-tool / cron caller typically closes
541	    // its read end on parent exit, silently dropping child writes. Fall
542	    // back to null when there is no tty (pipe-invoked / CI / Windows);
543	    // the log file is authoritative in that case.
544	    match std::fs::OpenOptions::new()
545	        .read(true)
546	        .write(true)
547	        .open("/dev/tty")
548	    {
549	        Ok(tty) => {
550	            debug!("detach: /dev/tty opened, child output → terminal");
551	            let out = tty.try_clone()?;
552	            cmd.stdout(Stdio::from(out));
553	            cmd.stderr(Stdio::from(tty));
554	        }
555	        Err(e) => {
556	            debug!("detach: /dev/tty unavailable ({e}), child output → null");
557	            cmd.stdout(Stdio::null());
558	            cmd.stderr(Stdio::null());
559	        }
560	    }
561	
562	    #[cfg(unix)]
563	    {
564	        use std::os::unix::process::CommandExt;
565	        unsafe {
566	            cmd.pre_exec(|| {
567	                libc::setsid();
568	                Ok(())
569	            });
570	        }
571	    }
572	
573	    let child = cmd.spawn()?;
574	    debug!("detach: spawned child pid={}", child.id());
575	    match &ctx.log {
576	        Some(log) => info!(
577	            "finalize: detached (pid {}), log: {}",
578	            child.id(),
579	            log.display()
580	        ),
581	        None => info!("finalize: detached (pid {})", child.id()),
582	    }
583	    Ok(())
584	}
585	
586	/// Run the `finalize` subcommand: preflight, then either detach a
587	/// child to do the work or do it inline.
588	pub fn finalize(ctx: &Context, params: &FinalizeParams) -> Result<(), Box<dyn std::error::Error>> {
589	    // Nothing to do — show help hint
590	    if params.squash.is_none() && !params.push {
591	        return Err("nothing to do (see --help for options)".into());
592	    }
593	
594	    debug!("finalize: entry params={params:?}");
595	
596	    // Validate synchronously before detaching so failures exit with a
597	    // visible non-zero status rather than hiding in the detached child's log.
598	    // Skip in --exec (the re-entered child already passed preflight in the parent).
599	    if !params.exec {
600	        preflight(params)?;
601	    }
602	
603	    let result = if params.detach && !params.exec {
604	        detach(ctx, params)
605	    } else {
606	        finalize_exec(params)
607	    };
608	    match &result {
609	        Ok(()) => debug!("finalize: exit ok"),
610	        Err(e) => {
611	            debug!("finalize: exit err={e}");
612	            // In the detached-child path the caller can't observe our
613	            // non-zero exit. Drop a failure marker so a later vc-x1
614	            // invocation can surface the problem.
615	            if params.exec {
616	                write_failure_marker(params, &e.to_string());
617	            }
618	        }
619	    }
620	    result
621	}
